// scripts/verify-op-purity.mjs
//
// Arch 2 Correction 2 (C2) — operation apply() handlers MUST NOT
// generate IDs. IDs are pre-generated by the caller and threaded through
// the payload. This enforces deterministic replay for collaboration
// and prevents subtle inverse-correctness bugs.
//
// Grep-style check inside src/operations/registry.js (the only file
// allowed to define apply functions today).

import { readFile } from 'node:fs/promises'
import { join } from 'node:path'

const REGISTRY_PATH = new URL('../src/operations/registry.js', import.meta.url).pathname
// Windows leading-slash adjustment
const REGISTRY_ABS = process.platform === 'win32'
  ? REGISTRY_PATH.replace(/^\//, '')
  : REGISTRY_PATH

const passed = []
const failed = []

const content = await readFile(REGISTRY_ABS, 'utf8')
const lines = content.split(/\r?\n/)

// Pattern 1: direct crypto.randomUUID() call
// Pattern 2: import { uid, uidIfc, newEntityIds } usage inside apply blocks
//
// Simple line-by-line walk. Whenever we're inside an `apply(state, payload)`
// function body, flag any ID-generation calls.

const FORBIDDEN_PATTERNS = [
  { re: /\bcrypto\.randomUUID\s*\(/,  label: 'crypto.randomUUID()' },
  { re: /\buid\s*\(/,                  label: 'uid()' },
  { re: /\buidIfc\s*\(/,               label: 'uidIfc()' },
  { re: /\bnewEntityIds\s*\(/,         label: 'newEntityIds()' },
]

// Track depth: we're "inside apply" between an `apply(` declaration and
// the matching closing brace. A simple bracket counter catches nested
// blocks (if/for) without parser overhead.
let inApply = false
let depth = 0
const offenders = []

for (let i = 0; i < lines.length; i++) {
  const line = lines[i]
  // Skip comments — leading // or single-line within block.
  const stripped = line.replace(/\/\/.*$/, '')

  // Detect apply( ... ) function declaration. Forms:
  //   apply(state, payload) {
  //   apply: (state, payload) => {
  //   apply: function (state, payload) {
  if (!inApply) {
    if (/\bapply\s*[:(]\s*(?:function\s*)?\(\s*[a-zA-Z_$][\w$]*\s*,\s*[a-zA-Z_$][\w$]*\s*\)\s*(?:=>\s*)?\{/.test(stripped)) {
      inApply = true
      depth = 1
      // Continue scanning this line for forbidden patterns after the `{`.
    } else {
      continue
    }
  }

  // Inside apply: check forbidden patterns.
  for (const { re, label } of FORBIDDEN_PATTERNS) {
    if (re.test(stripped)) {
      offenders.push(`${REGISTRY_ABS}:${i + 1}  ${label}  ${stripped.trim()}`)
    }
  }

  // Adjust depth by counting { } on the (uncommented) line.
  for (const ch of stripped) {
    if (ch === '{') depth++
    else if (ch === '}') depth--
  }
  if (depth <= 0) {
    inApply = false
    depth = 0
  }
}

if (offenders.length === 0) {
  passed.push('C2: no ID-generation calls inside any apply() function')
} else {
  failed.push(`C2: ${offenders.length} forbidden ID-generation calls inside apply():`)
  for (const o of offenders) failed.push(`   ${o}`)
}

console.log(`\nPASSED: ${passed.length}`)
for (const p of passed) console.log(`   ${p}`)
if (failed.length > 0) {
  console.log(`\nFAILED:`)
  for (const f of failed) console.log(`   ${f}`)
  process.exit(1)
}
console.log('\n✓ verify-op-purity passed.')
